@app.route("/aggregations/documents/by-status", methods=["GET"])
def aggregate_documents_by_status():
    pipeline = [
        {
            "$group": {
                "_id": "$status",
                "count": {"$sum": 1},
                "latest_created_at": {"$max": "$created_at"},
            }
        },
        {"$sort": {"count": -1}},
    ]

    results = [serialize_document(doc) for doc in documents_collection.aggregate(pipeline)]
    return jsonify(results)


